import { NextRequest, NextResponse } from "next/server"
import { connectDB } from "@/lib/db"
import Template from "@/models/Template"
import Variable from "@/models/Variable"
import { extractDocxVariables } from "@/lib/extractDocx"
import { extractXlsxVariablesFromBuffer } from "@/lib/extractXlsx"
import { autoMap } from "@/lib/autoMap"
import fs from "fs"
import path from "path"

export async function POST(req: NextRequest) {
  try {
    await connectDB()

    const formData = await req.formData()
    const file = formData.get("file") as File

    const bytes = await file.arrayBuffer()
    const buffer = Buffer.from(bytes)

    const dir = path.join(process.cwd(), "public", "uploads")
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true })
    }

    const uploadPath = `/uploads/${Date.now()}-${file.name}`
    const fullPath = path.join(process.cwd(), "public", uploadPath)

    fs.writeFileSync(fullPath, buffer)

    let variables: string[] = []
    const ext = file.name.split(".").pop()?.toLowerCase()

    if (ext === "docx") {
      variables = await extractDocxVariables(fullPath)
    } else if (ext === "xlsx") {
        console.log({ message: "xlsx upload" })
      variables = extractXlsxVariablesFromBuffer(buffer)
    } else {
      return NextResponse.json(
        { error: "Only DOCX and XLSX files are supported" },
        { status: 400 }
      )
    }

    const template = await Template.create({
      name: file.name,
      fileUrl: uploadPath,
      type: ext,
    })

    if (variables.length === 0) {
      return NextResponse.json({
        warning: "No variables found. Use {{variable}} format in template.",
        template,
        variables: [],
      })
    }

    const mapped = []
    const unmapped = []

    for (let v of variables) {
      const map = autoMap(v)

      await Variable.create({
        templateId: template._id,
        variable: v,
        mappedTo: map,
      })

      map ? mapped.push(v) : unmapped.push(v)
    }

    return NextResponse.json({ template, variables, mapped, unmapped })
  } catch (err) {
    console.error(err)
    return NextResponse.json({ error: "Upload failed" }, { status: 500 })
  }
}